const API_BASE_URL = '/api';

export interface EnvStats {
    ts: number;
    green_ratio: number;
    baseline_green_ratio: number;
    cover_change_pct: number;
    tree_alert: number;
    excavation_count: number;
    activity_count: number;
    payload: string;
}

export interface WaterReading {
    ts: number;
    ph: number;
    turbidity_ntu: number;
    temperature_c: number;
    alerts: string;
    recommendations: string;
}

export interface FiltrationStatus {
    ts: number;
    state: string;
    telemetry: {
        net_load_pct: number;
        bottle_clog_pct: number;
        flow_lpm: number;
    };
    actuators: {
        gears_active: boolean;
        backwash_on: boolean;
        pump_active: boolean;
    };
    last_action: {
        type: string;
        ts: number;
    };
}

export interface SystemHealth {
    score: number;
    status: 'EXCELLENT' | 'GOOD' | 'WARNING' | 'CRITICAL';
    reasons: string[];
}

export interface EnergyStats {
    day: string;
    energy_kwh: number;
    avg_power_w: number;
    samples: number;
}

export interface DistributionEvent {
    ts: number;
    home: string;
    path: string;
    cost: number;
    volume_liters: number;
}

export interface DistributionHistory {
    day: string;
    total_volume_liters: number;
}

export interface DashboardData {
    env: EnvStats | null;
    water: WaterReading | null;
    filtration: FiltrationStatus | null;
    energy: EnergyStats | null;
    health: SystemHealth | null;
    distribution?: DistributionEvent[];
}


const fetchWithAuth = async (url: string, options: RequestInit = {}) => {
    const token = localStorage.getItem('token');
    const headers = {
        ...options.headers,
        ...(token ? { 'Authorization': `Bearer ${token}` } : {})
    };
    return fetch(url, { ...options, headers });
};

export const fetchLatestStats = async (): Promise<DashboardData> => {
    const response = await fetchWithAuth(`${API_BASE_URL}/latest-stats`);
    if (!response.ok) throw new Error('Failed to fetch stats');
    return response.json();
};

export const fetchHistory = async () => {
    const response = await fetchWithAuth(`${API_BASE_URL}/history`);
    if (!response.ok) throw new Error('Failed to fetch history');
    return response.json();
};

export const fetchEnergyHistory = async () => {
    const response = await fetchWithAuth(`${API_BASE_URL}/energy-history`);
    if (!response.ok) throw new Error('Failed to fetch energy history');
    return response.json();
};

export const fetchDistributionLatest = async (): Promise<DistributionEvent[]> => {
    const response = await fetchWithAuth(`${API_BASE_URL}/distribution/latest`);
    if (!response.ok) throw new Error('Failed to fetch distribution status');
    return response.json();
};

export const fetchDistributionHistory = async (): Promise<DistributionHistory[]> => {
    const response = await fetchWithAuth(`${API_BASE_URL}/distribution/history`);
    if (!response.ok) throw new Error('Failed to fetch distribution history');
    return response.json();
};

export const systemControl = async (action: string): Promise<any> => {
    const response = await fetchWithAuth(`${API_BASE_URL}/control/${action}`, { method: 'POST' });
    if (!response.ok) throw new Error('Control action failed');
    return response.json();
};

export const fetchForecast = async (): Promise<any> => {
    const response = await fetchWithAuth(`${API_BASE_URL}/forecast`);
    if (!response.ok) throw new Error('Forecast fetch failed');
    return response.json();
};

// ASAASE Robot Control System API Client

const API_BASE = '/api/asaase';

export interface RobotStatus {
  ground: {
    online: boolean;
    battery_pct: number;
    last_seen: number;
  };
  aqua: {
    online: boolean;
    battery_pct: number;
    last_seen: number;
  };
  alert_count_24h: number;
  critical_count_24h: number;
}

export type ControlMode = 'MANUAL' | 'SEMI_AUTO' | 'FULLY_AUTO';

export interface RobotSettings {
  robot_id: string;
  control_mode: ControlMode;
  last_command?: string;
  last_command_ts?: number;
  pending_action?: string;
  pending_action_ts?: number;
}

export interface BaseSettings {
  operation_mode: ControlMode;
}

export interface PendingApproval {
  id: number;
  robot_id: string;
  action_type: string;
  severity: string;
  lat: number;
  lon: number;
  created_at: number;
  status: 'PENDING' | 'APPROVED' | 'REJECTED' | 'EXPIRED';
}


export interface GroundTelemetry {

  id: number;
  ts: number;
  robot_id: string;
  gps_lat: number;
  gps_lon: number;
  soil_classification: 'CLEAN' | 'MODERATE' | 'CRITICAL';
  confidence_score: number;
  dispenser_action: 'NONE' | 'SEEDS_ONLY' | 'BIOCHAR_AND_SEEDS';
  battery_pct: number;
  patrol_waypoint_index: number;
}

export interface AquaTelemetry {
  id: number;
  ts: number;
  robot_id: string;
  gps_lat: number;
  gps_lon: number;
  turbidity_ntu: number;
  ph_value: number;
  camera_water_classification: 'CLEAN' | 'MODERATE' | 'CRITICAL';
  dual_stream_verdict: 'CLEAN' | 'MODERATE' | 'CRITICAL';
  neutralizer_dispensed_ml: number;
  dye_marker_dropped: boolean;
  battery_pct: number;
}

export interface AsaaseAlert {
  id: number;
  ts: number;
  robot_id: string;
  severity: 'MODERATE' | 'CRITICAL';
  gps_lat: number;
  gps_lon: number;
  alert_type: 'SOIL' | 'WATER' | 'ROBOT_OFFLINE';
  sms_sent: number;
  report_generated: number;
  message: string;
}

export interface RemediationReport {
  id: number;
  alert_id: number;
  generated_at: number;
  report_en: string; // JSON string
  report_tw: string; // JSON string
  exported: number;
}

const getAuthHeader = (): { Authorization?: string } => {
    const token = localStorage.getItem('token');
    return token ? { 'Authorization': `Bearer ${token}` } : {};
};

export const fetchAsaaseStatus = async (): Promise<RobotStatus> => {
  const res = await fetch(`${API_BASE}/status`);
  return res.json();
};

export const fetchGroundLatest = async (): Promise<GroundTelemetry[]> => {
  const res = await fetch(`${API_BASE}/ground/latest`);
  return res.json();
};

export const fetchAquaLatest = async (): Promise<AquaTelemetry[]> => {
  const res = await fetch(`${API_BASE}/aqua/latest`);
  return res.json();
};

export const fetchGroundHeatmap = async (): Promise<any> => {
  const res = await fetch(`${API_BASE}/ground/heatmap`);
  return res.json();
};

export const fetchAquaHeatmap = async (): Promise<any> => {
  const res = await fetch(`${API_BASE}/aqua/heatmap`);
  return res.json();
};

export const fetchAsaaseAlerts = async (page = 1, limit = 10): Promise<AsaaseAlert[]> => {
  const res = await fetch(`${API_BASE}/alerts?page=${page}&limit=${limit}`);
  return res.json();
};

export const fetchReport = async (alertId: number): Promise<RemediationReport> => {
  const res = await fetch(`${API_BASE}/reports/${alertId}`);
  if (!res.ok) throw new Error('Report not found');
  return res.json();
};

export const uploadGroundWaypoints = async (robot_id: string, waypoints: {lat: number, lon: number}[]) => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }

  const res = await fetch(`${API_BASE}/ground/waypoints`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ robot_id, waypoints })
  });
  return res.json();
};

export const uploadAquaRoute = async (robot_id: string, waypoints: {lat: number, lon: number}[]) => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }

  const res = await fetch(`${API_BASE}/aqua/route`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ robot_id, waypoints })
  });
  return res.json();
};

export const fetchControlSettings = async (robotId: string): Promise<RobotSettings> => {
  const res = await fetch(`${API_BASE}/control/settings/${robotId}`);
  return res.json();
};

export const updateControlMode = async (robot_id: string, mode: ControlMode) => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }
  const res = await fetch(`${API_BASE}/control/mode`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ robot_id, mode })
  });
  return res.json();
};

export const sendManualCommand = async (robot_id: string, command: string) => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }
  const res = await fetch(`${API_BASE}/control/manual`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ robot_id, command })
  });
  return res.json();
};

export const fetchBaseSettings = async (): Promise<BaseSettings> => {

  const res = await fetch(`${API_BASE}/base/settings`);
  return res.json();
};

export const updateBaseMode = async (mode: ControlMode) => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }
  const res = await fetch(`${API_BASE}/base/mode`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ mode })
  });
  return res.json();
};

export const fetchPendingApprovals = async (): Promise<PendingApproval[]> => {
  const res = await fetch(`${API_BASE}/control/approvals`);
  return res.json();
};

export const approveAction = async (approval_id: number, action: 'APPROVED' | 'REJECTED') => {
  const headers: HeadersInit = { 'Content-Type': 'application/json' };
  const auth = getAuthHeader();
  if (auth.Authorization) {
    (headers as any).Authorization = auth.Authorization;
  }
  const res = await fetch(`${API_BASE}/control/approve`, {
    method: 'POST',
    headers,
    body: JSON.stringify({ approval_id, action })
  });
  return res.json();
};

