import React, { useEffect, useCallback, useState } from 'react';
import { Gamepad, ChevronUp, ChevronDown, ChevronLeft, ChevronRight, Zap, Shield, Sparkles, Sprout, FlaskConical, Camera, Radar, Activity, Droplet, Wind, Terminal, Waves, Bot } from 'lucide-react';
import type { RobotSettings } from '../../asaaseApi';
import * as api from '../../asaaseApi';

interface ControlHubProps {
  robotId: string;
  settings: RobotSettings | null;
  baseSettings: api.BaseSettings | null;
  approvals: api.PendingApproval[];
  onSettingsUpdate?: () => void;
  onRobotChange?: (id: 'GROUND_01' | 'AQUA_01') => void;
  minimal?: boolean;
}

const ControlHub: React.FC<ControlHubProps> = ({ 
  robotId, 
  settings, 
  baseSettings, 
  approvals, 
  onSettingsUpdate,
  onRobotChange, 
  minimal 
}) => {
  const isGround = robotId.startsWith('GROUND');
  const safeApprovals = Array.isArray(approvals) ? approvals : [];
  const [dosingVal, setDosingVal] = useState(50); // Default 50g/m2 or 50ml
  const [showManualConfirm, setShowManualConfirm] = useState(false);
  const [pendingManualCmd, setPendingManualCmd] = useState<string | null>(null);

  const sendCommand = useCallback(async (command: string) => {
    if (currentControlMode === 'FULLY_AUTO' && command !== 'HALT_ALL') {
      alert("Manual override locked in AUTO mode. Switch to MANUAL first.");
      return;
    }

    if (command !== 'HALT_ALL' && !showManualConfirm && currentControlMode === 'MANUAL') {
        setPendingManualCmd(command);
        setShowManualConfirm(true);
        return;
    }

    try {
      await api.sendManualCommand(robotId, command);
      onSettingsUpdate?.();
    } catch (e) {
      console.error("Command failed", e);
    }
  }, [robotId, settings, showManualConfirm, onSettingsUpdate]);

  const confirmManual = () => {
      if (pendingManualCmd) {
          api.sendManualCommand(robotId, pendingManualCmd);
          setPendingManualCmd(null);
          setShowManualConfirm(false);
          onSettingsUpdate?.();
      }
  };

  const handleModeChange = async (mode: api.ControlMode) => {
    try {
      await api.updateControlMode(robotId, mode);
      onSettingsUpdate?.();
    } catch (e) {
      console.error("Mode update failed", e);
    }
  };

  const handleBaseModeChange = async (mode: api.ControlMode) => {
    try {
      await api.updateBaseMode(mode);
      onSettingsUpdate?.();
    } catch (e) {
      console.error("Base mode update failed", e);
    }
  };

  const handleApprove = async (id: number, action: 'APPROVED' | 'REJECTED') => {
    try {
      await api.approveAction(id, action);
      onSettingsUpdate?.();
    } catch (e) {
      console.error("Approval failed", e);
    }
  };

  const currentControlMode = settings?.control_mode || 'FULLY_AUTO';
  const currentBaseMode = baseSettings?.operation_mode || 'FULLY_AUTO';

  if (minimal) {
    if (safeApprovals.length === 0) return null;
    return (
      <div className="space-y-4 p-5 rounded-2xl border bg-blue-900/10 border-blue-500/20 backdrop-blur-md">
         <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Shield size={16} className="text-blue-400" />
              <span className="text-[10px] font-black uppercase tracking-widest text-blue-200">Pending Handshake</span>
            </div>
            <span className="bg-blue-500 text-white text-[9px] font-black px-2 py-0.5 rounded-md">{safeApprovals.length}</span>
         </div>
         <div className="space-y-2">
            {safeApprovals.slice(0, 1).map((appr) => (
              <div key={appr.id} className="bg-slate-900/60 p-3 rounded-xl border border-white/5 space-y-2">
                <div className="text-[9px] font-bold text-slate-500 uppercase flex justify-between">
                    <span>{appr.robot_id}</span>
                    <span className="text-amber-500">{appr.severity}</span>
                </div>
                <div className="text-[10px] text-white font-black italic">{appr.action_type}</div>
                <div className="flex gap-2 mt-2">
                   <button onClick={() => handleApprove(appr.id, 'APPROVED')} className="flex-1 py-1.5 bg-emerald-500/20 hover:bg-emerald-500 text-emerald-400 hover:text-white text-[8px] font-black uppercase rounded-lg border border-emerald-500/20 transition-all">Approve</button>
                   <button onClick={() => handleApprove(appr.id, 'REJECTED')} className="flex-1 py-1.5 bg-red-500/20 hover:bg-red-500 text-red-400 hover:text-white text-[8px] font-black uppercase rounded-lg border border-red-500/20 transition-all">Abort</button>
                </div>
              </div>
            ))}
         </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col gap-8">

        {/* TOP COMMAND BAR */}
        <div className="p-8 border-b border-white/5 bg-gradient-to-b from-white/5 to-transparent relative z-10 rounded-[2rem] bg-slate-900/20">
           <div className="flex items-center justify-between mb-8">
              <div className="flex items-center gap-3">
                 <Terminal size={18} className="text-emerald-400 animate-pulse" />
                 <h4 className="text-[12px] font-black text-white uppercase tracking-[0.3em] italic">Direct Interface</h4>
              </div>
              <div className="flex bg-white/5 p-1 rounded-xl border border-white/5">
                 <button 
                    onClick={() => onRobotChange?.('GROUND_01')} 
                    className={`px-3 py-1 rounded-lg text-[8px] font-black uppercase transition-all ${robotId === 'GROUND_01' ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' : 'text-slate-500 hover:text-slate-300'}`}
                 >
                    ROVER
                 </button>
                 <button 
                    onClick={() => onRobotChange?.('AQUA_01')} 
                    className={`px-3 py-1 rounded-lg text-[8px] font-black uppercase transition-all ${robotId === 'AQUA_01' ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/20' : 'text-slate-500 hover:text-slate-300'}`}
                 >
                    SCOUT
                 </button>
              </div>
           </div>

           <div className="flex flex-col gap-4">
              <div className="flex items-center gap-2">
                 <Gamepad size={20} className="text-slate-600" />
                 <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Control State</span>
              </div>
              <div className="flex flex-wrap gap-2 bg-white/5 p-2 rounded-xl border border-white/5">
                 {(['MANUAL', 'SEMI_AUTO', 'FULLY_AUTO'] as const).map((m) => (
                    <button 
                       key={m}
                       onClick={() => handleModeChange(m)}
                       className={`px-3 py-2 flex-1 min-w-[30%] rounded-lg text-[9px] font-black uppercase transition-all ${currentControlMode === m ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/20' : 'bg-black/20 text-slate-400 border border-white/5 hover:bg-white/10'}`}
                    >
                       {m.replace('_', ' ')}
                    </button>
                 ))}
              </div>
           </div>
        </div>

        {/* MODE QUICK SWITCH (Bilingual) */}
        <div className="flex gap-4 px-4">
           <div className="flex-1 bg-slate-800/20 p-5 rounded-[2rem] border border-white/5 flex items-center justify-between group hover:border-emerald-500/20 transition-all">
              <div className="flex flex-col">
                 <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Global Ops</span>
                 <span className="text-[10px] font-black text-slate-200 uppercase italic">Fleet Mode</span>
              </div>
              <div className="flex gap-1.5">
                 {(['MANUAL', 'FULLY_AUTO'] as const).map((bm) => (
                    <button 
                       key={bm}
                       onClick={() => handleBaseModeChange(bm)}
                       className={`px-4 py-2 rounded-xl text-[8px] font-black uppercase border transition-all ${currentBaseMode === bm ? 'bg-white border-white text-black' : 'border-white/5 text-slate-600 hover:text-slate-400'}`}
                    >
                       {bm === 'MANUAL' ? 'Manual / Akwankyerɛ' : 'Auto / Dwumadie'}
                    </button>
                 ))}
              </div>
           </div>
        </div>

        {/* 🎮 DIRECT MANUAL DECK */}
        <div className="flex-1 p-8 flex flex-col gap-8">
           <div className="grid grid-cols-2 gap-6">
              <div className="space-y-4">
                  <div className="flex items-center gap-2 mb-2">
                     <Radar size={16} className="text-emerald-500/40" />
                     <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Navigation / Akwankyerɛ</span>
                  </div>
                  <div className="grid grid-cols-3 gap-2">
                     <div />
                     <button onClick={() => sendCommand('MOVE_FORWARD')} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 flex flex-col items-center group transition-all">
                        <ChevronUp size={24} className="text-white group-hover:text-emerald-400" />
                        <span className="text-[7px] font-black mt-1">ANIM</span>
                     </button>
                     <div />
                     <button onClick={() => sendCommand('MOVE_LEFT')} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 flex flex-col items-center group transition-all">
                        <ChevronLeft size={24} className="text-white group-hover:text-emerald-400" />
                        <span className="text-[7px] font-black mt-1">BENKUM</span>
                     </button>
                     <button onClick={() => sendCommand('HALT_ALL')} className="p-4 bg-red-500/20 hover:bg-red-500 rounded-2xl border border-red-500/40 flex flex-col items-center group transition-all">
                        <Activity size={24} className="text-red-500 group-hover:text-white" />
                        <span className="text-[7px] font-black mt-1 text-red-400 group-hover:text-white">GYAE</span>
                     </button>
                     <button onClick={() => sendCommand('MOVE_RIGHT')} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 flex flex-col items-center group transition-all">
                        <ChevronRight size={24} className="text-white group-hover:text-emerald-400" />
                        <span className="text-[7px] font-black mt-1">NIFA</span>
                     </button>
                     <div />
                     <button onClick={() => sendCommand('MOVE_BACK')} className="p-4 bg-white/5 hover:bg-white/10 rounded-2xl border border-white/5 flex flex-col items-center group transition-all">
                        <ChevronDown size={24} className="text-white group-hover:text-emerald-400" />
                        <span className="text-[7px] font-black mt-1">AKYI</span>
                     </button>
                     <div />
                  </div>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => sendCommand('SCAN_SOIL')} className="p-6 rounded-3xl bg-slate-950/40 hover:bg-emerald-500/10 border border-white/5 hover:border-emerald-500/20 transition-all group flex flex-col items-center justify-center gap-3">
                    <Radar size={24} className="text-emerald-400 group-hover:scale-110 transition-transform" />
                    <div className="text-center">
                        <span className="text-[10px] font-black text-emerald-400 group-hover:text-white uppercase block italic">Soil Scan</span>
                        <span className="text-[7px] font-bold text-slate-600 uppercase italic">Hwɛ dɔteɛ mu</span>
                    </div>
                </button>
                <button onClick={() => sendCommand('DISPENSE_SEEDS')} className="p-6 rounded-3xl bg-emerald-500/10 hover:bg-emerald-500 border border-emerald-500/20 transition-all group flex flex-col items-center justify-center gap-3 shadow-lg relative overflow-hidden">
                    <div className="absolute inset-0 bg-emerald-500/20 animate-pulse group-hover:bg-transparent"></div>
                    <Sprout size={24} className="text-emerald-400 group-hover:text-white animate-bounce relative z-10" />
                    <div className="text-center relative z-10">
                        <span className="text-[10px] font-black text-emerald-400 group-hover:text-white uppercase block italic">Planting Seeds</span>
                        <span className="text-[7px] font-bold text-emerald-500 group-hover:text-white/80 uppercase">Gu aba no</span>
                    </div>
                </button>
                <button onClick={() => sendCommand('SAMPLE_WATER')} className="p-6 rounded-3xl bg-slate-950/40 hover:bg-blue-500/10 border border-white/5 hover:border-blue-500/20 transition-all group flex flex-col items-center justify-center gap-3">
                    <Droplet size={24} className="text-blue-400 group-hover:scale-110 transition-transform" />
                    <div className="text-center">
                        <span className="text-[10px] font-black text-blue-400 group-hover:text-white uppercase block italic">Water Probe</span>
                        <span className="text-[7px] font-bold text-slate-600 uppercase italic">Hwɛ nsuo no</span>
                    </div>
                </button>
                <button onClick={() => sendCommand('DEPLO_NEUTRAL')} className="p-6 rounded-3xl bg-blue-500/10 hover:bg-blue-500 border border-blue-500/20 transition-all group flex flex-col items-center justify-center gap-3 shadow-lg">
                    <FlaskConical size={24} className="text-blue-400 group-hover:text-white animate-pulse" />
                    <div className="text-center">
                        <span className="text-[10px] font-black text-blue-400 group-hover:text-white uppercase block italic">Dispense Chem</span>
                        <span className="text-[7px] font-bold text-blue-500 group-hover:text-white/80 uppercase">Gu aduro no</span>
                    </div>
                </button>
              </div>
           </div>

           {/* 🧪 PAYLOAD STATION (Dosing Sliders) */}
           <div className="bg-slate-900/60 p-10 rounded-[3rem] border border-white/10 flex flex-col gap-8 shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-10 opacity-5 group-hover:opacity-10 transition-opacity rotate-12">
                 <FlaskConical size={120} />
              </div>
              <div className="flex items-center justify-between relative z-10">
                 <div className="flex items-center gap-3">
                    <Zap size={20} className="text-amber-500 animate-pulse" />
                    <h4 className="text-[12px] font-black text-white uppercase tracking-[0.3em] italic">Payload Rack / Aduro</h4>
