                 <div className="flex items-center gap-4 bg-black/40 px-6 py-2 rounded-2xl border border-white/5">
                    <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Target Dose</span>
                    <span className="text-xl font-black text-emerald-400 italic tracking-tighter">{dosingVal}<span className="text-[10px] font-bold text-slate-600 ml-1">G/M²</span></span>
                 </div>
              </div>
              <div className="space-y-4 relative z-10">
                 <input 
                    type="range" 
                    min="10" max="250" 
                    value={dosingVal} 
                    onChange={(e) => setDosingVal(parseInt(e.target.value))}
                    className="w-full h-1.5 bg-white/5 rounded-lg appearance-none cursor-pointer accent-emerald-500 active:accent-emerald-400" 
                 />
                 <div className="flex justify-between text-[8px] font-black text-slate-600 uppercase tracking-widest italic">
                    <span>Min Dose (10g)</span>
                    <span>Max Capacity (250g)</span>
                 </div>
              </div>
           </div>
        </div>

        {/* 🚨 EMERGENCY STATION */}
        <div className="mt-auto grid grid-cols-2 gap-6 p-8 bg-gradient-to-t from-red-500/10 to-transparent rounded-b-[3rem]">
           <button onClick={() => sendCommand('RTB_PULSE')} className="p-6 bg-slate-900/60 hover:bg-white text-slate-400 hover:text-black rounded-3xl border border-white/5 transition-all flex items-center justify-center gap-4 group">
              <Radar size={22} className="group-hover:animate-ping" />
              <div className="text-left">
                 <div className="text-[10px] font-black uppercase tracking-widest mb-0.5">Return to Base</div>
                 <div className="text-[7px] font-black uppercase opacity-60 italic">Kɔ Fie Mpofirim</div>
