           </button>
        </div>

        {/* PROMPT/CONFIRM MODAL */}
        {showManualConfirm && (
           <div className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-md flex items-center justify-center p-8">
              <div className="bg-slate-900 border border-white/10 p-12 rounded-[3.5rem] shadow-[0_0_100px_rgba(239,68,68,0.2)] max-w-lg w-full text-center space-y-10 animate-in zoom-in-95 duration-300">
