                    <button onClick={() => { setPendingManualCmd(null); setShowManualConfirm(false); }} className="p-5 bg-white/5 hover:bg-white/10 text-white text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl border border-white/10 transition-all">Cancel / Ansa</button>
                    <button onClick={confirmManual} className="p-5 bg-emerald-500 hover:bg-emerald-400 text-white text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl shadow-lg shadow-emerald-500/20 transition-all">Confirm / Yiw</button>
                 </div>
              </div>
           </div>
        )}
    </div>
  );
};

