import React from 'react';
import { Bot, Battery, Signal } from 'lucide-react';
import type { RobotStatus } from '../../asaaseApi';

interface RobotStatusBarProps {
  status: RobotStatus;
}

const RobotStatusBar: React.FC<RobotStatusBarProps> = ({ status }) => {
  const renderCard = (label: string, data: any, type: 'ground' | 'aqua') => {
    const isOnline = data.online;
    const batteryColor = data.battery_pct > 70 ? 'text-emerald-400' : data.battery_pct > 30 ? 'text-yellow-400' : 'text-red-400';

    return (
      <div className="bg-slate-800/50 border border-white/5 p-4 rounded-2xl flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className={`p-3 rounded-xl bg-${type === 'ground' ? 'amber' : 'blue'}-500/10`}>
             <Bot size={24} className={`text-${type === 'ground' ? 'amber' : 'blue'}-400`} />
          </div>
          <div>
            <div className="flex items-center gap-2">
              <span className="font-bold text-slate-200">{label}</span>
              <span className={`px-2 py-0.5 rounded-full text-[10px] font-black uppercase ${isOnline ? 'bg-emerald-500/20 text-emerald-400' : 'bg-red-500/20 text-red-400'}`}>
                {isOnline ? 'Online' : 'Offline'}
              </span>
            </div>
            <div className="text-xs text-slate-500 flex items-center gap-2 mt-1">
              <Signal size={12} />
              Last seen: {data.last_seen > 0 ? new Date(data.last_seen * 1000).toLocaleTimeString() : 'Never'}
            </div>
          </div>
        </div>

        <div className="flex gap-6">
          <div className="text-right">
            <div className="text-xs text-slate-500 font-medium">Battery</div>
            <div className={`text-lg font-bold flex items-center gap-1 ${batteryColor}`}>
              <Battery size={16} />
              {data.battery_pct}%
            </div>
          </div>
          <div className="text-right">
            <div className="text-xs text-slate-500 font-medium">Health</div>
            <div className="text-lg font-bold text-slate-200">
               {isOnline ? 'Stable' : 'Unknown'}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {renderCard('ASAASE GROUND', status.ground, 'ground')}
      {renderCard('ASAASE AQUA', status.aqua, 'aqua')}
    </div>
  );
};

export default RobotStatusBar;

import React from 'react';
import { Activity, Clock } from 'lucide-react';

interface LogEntry {
  ts: number;
  source: string;
  msg: string;
  type: 'INFO' | 'WARN' | 'CRIT' | 'SYS';
}

const SensorLog: React.FC = () => {
  // Simulated Log Data
  const logs: LogEntry[] = [
    { ts: Date.now() / 1000, source: 'GROUND_01', msg: 'Soil scan complete: Mercury detection (0.88mg/kg)', type: 'WARN' },
    { ts: Date.now() / 1000 - 60, source: 'AQUA_01', msg: 'Turbidity stable at 45.0 NTU', type: 'INFO' },
    { ts: Date.now() / 1000 - 120, source: 'BASE', msg: 'GSM Signal Handshake: 94%', type: 'SYS' },
    { ts: Date.now() / 1000 - 180, source: 'GROUND_01', msg: 'Biochar dispenser engaged at GH_LOC_001', type: 'CRIT' },
    { ts: Date.now() / 1000 - 240, source: 'AQUA_01', msg: 'Route segment 4 validated', type: 'INFO' },
    { ts: Date.now() / 1000 - 300, source: 'BASE', msg: 'Encryption keys rotated', type: 'SYS' },
  ];

  const getColor = (type: string) => {
    switch (type) {
      case 'WARN': return 'text-amber-400';
      case 'CRIT': return 'text-red-400';
      case 'SYS': return 'text-blue-400';
      default: return 'text-slate-400';
    }
  };

  return (
    <div className="flex flex-col h-full bg-[#1a1d23]/40 rounded-xl border border-white/5 overflow-hidden font-mono">
      <div className="p-4 border-b border-white/5 flex items-center justify-between bg-black/20">
        <div className="flex items-center gap-2">
          <Activity size={16} className="text-emerald-500" />
          <span className="text-[10px] font-black text-slate-200 uppercase tracking-widest">Tactical Sensor Log</span>
        </div>
        <Clock size={14} className="text-slate-600" />
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
        {logs.map((log, i) => (
          <div key={i} className="flex gap-3 text-[9px] border-l border-white/10 pl-3 py-1 group hover:bg-white/5 transition-all">
             <span className="text-slate-600 shrink-0">[{new Date(log.ts * 1000).toLocaleTimeString([], {hour12: false})}]</span>
             <span className="text-emerald-500/80 font-bold shrink-0">{log.source}</span>
             <span className={`${getColor(log.type)} uppercase tracking-tighter transition-colors`}>{log.msg}</span>
          </div>
        ))}
      </div>

      <div className="p-4 bg-black/40 border-t border-white/5 text-right">
         <span className="text-[8px] font-black text-slate-700 uppercase tracking-[0.2em]">Operational Pulse Active</span>
      </div>
    </div>
  );
};

export default SensorLog;

import React from 'react';

interface TelemetryTableProps {
  data: any[];
  type: 'ground' | 'aqua';
}

const TelemetryTable: React.FC<TelemetryTableProps> = ({ data, type }) => {
  return (
    <div className="bg-slate-800/50 border border-white/5 rounded-2xl overflow-hidden">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-900/50 text-slate-500 text-[10px] uppercase font-black tracking-widest">
            <tr>
              <th className="px-6 py-4">Time</th>
              <th className="px-6 py-4">Robot ID</th>
              {type === 'ground' ? (
                <>
                  <th className="px-6 py-4">Classification</th>
                  <th className="px-6 py-4">Confidence</th>
                  <th className="px-6 py-4">Action</th>
                </>
              ) : (
                <>
                  <th className="px-6 py-4">Turbidity (NTU)</th>
                  <th className="px-6 py-4">pH</th>
                  <th className="px-6 py-4">Verdict</th>
                </>
              )}
              <th className="px-6 py-4">Battery</th>
            </tr>
          </thead>
          <tbody className="text-sm divide-y divide-white/5">
            {data.length === 0 ? (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-slate-500 uppercase tracking-widest font-bold text-[10px]">
                  Waiting for telemetry...
                </td>
              </tr>
            ) : (
              data.map((row, idx) => (
                <tr key={idx} className="hover:bg-white/5 transition-colors">
                  <td className="px-6 py-4 text-slate-400 font-mono text-xs">
                    {new Date(row.ts * 1000).toLocaleTimeString()}
                  </td>
                  <td className="px-6 py-4 font-bold text-slate-200">{row.robot_id}</td>
                  {type === 'ground' ? (
                    <>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-0.5 rounded-lg text-[10px] font-bold ${
                          row.soil_classification === 'CRITICAL' ? 'text-red-400' : 'text-emerald-400'
                        }`}>
                          {row.soil_classification}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-slate-400 font-mono">{row.confidence_score}%</td>
                      <td className="px-6 py-4 text-xs text-slate-400">{row.dispenser_action}</td>
                    </>
                  ) : (
                    <>
                      <td className="px-6 py-4 text-slate-400 font-mono">{row.turbidity_ntu?.toFixed(2) || '0.00'}</td>
                      <td className="px-6 py-4 text-slate-400 font-mono">{row.ph_value?.toFixed(2) || '0.00'}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-0.5 rounded-lg text-[10px] font-bold ${
                          row.dual_stream_verdict === 'CRITICAL' ? 'text-red-400' : 'text-emerald-400'
                        }`}>
                          {row.dual_stream_verdict}
                        </span>
                      </td>
                    </>
                  )}
                  <td className="px-6 py-4 text-slate-400 font-mono text-xs">{row.battery_pct}%</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TelemetryTable;

import React from 'react';
import { MousePointer2, Send, Trash2, List } from 'lucide-react';

interface WaypointEditorProps {
  waypoints: {lat: number, lon: number}[];
  onClear: () => void;
  onUpload: (target: 'GROUND_01' | 'AQUA_01') => void;
  selectedRobot: 'GROUND_01' | 'AQUA_01';
  setSelectedRobot: (id: 'GROUND_01' | 'AQUA_01') => void;
}

const WaypointEditor: React.FC<WaypointEditorProps> = ({ waypoints, onClear, onUpload, selectedRobot, setSelectedRobot }) => {
  return (
    <div className="bg-slate-800/50 border border-white/5 p-6 rounded-2xl">
      <div className="flex items-center justify-between mb-6">
        <h3 className="font-bold text-slate-200 flex items-center gap-2">
          <MousePointer2 size={18} className="text-emerald-400" />
          Waypoint Editor
        </h3>
        <div className="flex gap-2">
           <select 
             value={selectedRobot} 
             onChange={(e) => setSelectedRobot(e.target.value as any)}
             className="bg-slate-900 border border-white/10 rounded-lg px-3 py-1 text-xs text-slate-200 outline-none"
           >
             <option value="GROUND_01">GROUND_01</option>
             <option value="AQUA_01">AQUA_01</option>
           </select>
        </div>
      </div>

      <div className="space-y-3 max-h-[300px] overflow-y-auto mb-6 pr-2">
        {waypoints.length === 0 ? (
          <div className="text-center py-8 text-slate-500 text-sm border border-dashed border-white/10 rounded-xl">
            Click on the map to add waypoints
          </div>
        ) : (
          waypoints.map((wp, idx) => (
            <div key={idx} className="flex items-center justify-between p-3 bg-slate-900/50 rounded-xl border border-white/5">
              <div className="flex items-center gap-3">
                <span className="w-6 h-6 rounded-full bg-emerald-500/20 text-emerald-400 flex items-center justify-center text-[10px] font-bold">
                  {idx + 1}
                </span>
                <span className="text-xs text-slate-400 font-mono">
                  {wp.lat?.toFixed(6) || '0.000000'}, {wp.lon?.toFixed(6) || '0.000000'}
                </span>
              </div>
              <List size={14} className="text-slate-600" />
            </div>
          ))
        )}
      </div>

      <div className="grid grid-cols-2 gap-3">
        <button 
          onClick={onClear}
          className="flex items-center justify-center gap-2 py-3 bg-slate-700/50 hover:bg-slate-700 text-slate-300 rounded-xl transition-colors text-sm font-bold"
        >
          <Trash2 size={16} />
          Clear
        </button>
        <button 
          disabled={waypoints.length === 0}
          onClick={() => onUpload(selectedRobot)}
          className="flex items-center justify-center gap-2 py-3 bg-emerald-500 hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl transition-all shadow-[0_0_20px_rgba(16,185,129,0.2)] text-sm font-bold"
        >
          <Send size={16} />
          Upload
        </button>
      </div>
    </div>
  );
};

export default WaypointEditor;
